17	describe('POST /api/cards/:id/comments', () => {
18	  let server, baseUrl, cardId;
19	
20	  before(async () => {
21	    initDb(':memory:');
22	    const card = createCard({ title: 'Test Card' });
23	    cardId = card.id;
24	    const app = createApp();
25	    ({ server, baseUrl } = await startTestServer(app));
26	  });
27	
28	  after(async () => {
29	    await stopServer(server);
30	    closeDb();
