116	    const res = await fetch(`${baseUrl}/api/cards/nonexistent-id/comments`, {
117	      method: 'POST',
118	      headers: { 'Content-Type': 'application/json' },
119	      body: JSON.stringify({ author: 'Alice', content: 'Hello' }),
120	    });
121	    const body = await res.json();
