const jsonSpy = vi.fn();
const emptyBody = mockResponse(null, { status: 200, headers: { 'content-length': '0' } });
emptyBody.json = jsonSpy;
fetchMock.mockResolvedValue(emptyBody);
// assert: result === null AND jsonSpy was never called
```

### Implementation additions to `apiFetch`

```js
  // After the !response.ok block:
  if (response.status === 204 || response.headers.get('content-length') === '0') {
    return null;
  }
  try {
    return await response.json();
  } catch (err) {
    throw new ApiError(`Failed to parse response: ${err.message}`, response.status, null);
  }
```

