  ✓ calls fetch once with URL '/api/cards'
  ✓ does NOT include 'Content-Type' in the headers argument

describe('createCard')
  ✓ calls fetch with method 'POST' and URL '/api/cards'
  ✓ sends body: JSON.stringify(data)
  ✓ sets Content-Type: application/json in the headers argument

describe('updateCard')
  ✓ calls fetch with method 'PATCH' and URL '/api/cards/<id>'
  ✓ sends body: JSON.stringify(data)
  ✓ sets Content-Type: application/json in the headers argument

describe('deleteCard')
  ✓ calls fetch with method 'DELETE' and URL '/api/cards/<id>'
  ✓ does NOT include 'Content-Type' in the headers argument

describe('createComment')
  ✓ calls fetch with method 'POST' and URL '/api/cards/<cardId>/comments'
  ✓ sends body: JSON.stringify(data)
  ✓ sets Content-Type: application/json in the headers argument
```

Setup pattern (use `mockResponse` helper):

```js
import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { fetchCards, createCard, updateCard, deleteCard, createComment, ApiError } from './client.js';

// ... mockResponse helper here ...

describe('fetchCards', () => {
  let fetchMock;
  beforeEach(() => {
    fetchMock = vi.fn().mockResolvedValue(mockResponse([]));
    vi.stubGlobal('fetch', fetchMock);
  });
  afterEach(() => vi.unstubAllGlobals());

  it('calls fetch with URL /api/cards', async () => {
    await fetchCards();
    expect(fetchMock).toHaveBeenCalledWith('/api/cards', expect.anything());
  });

  it('does not set Content-Type header', async () => {
    await fetchCards();
    const [, options] = fetchMock.mock.calls[0];
    expect(options.headers).not.toHaveProperty('Content-Type');
  });
});
```

Note: `fetchCards` does **not** set an explicit `method` (browser defaults to GET); its test only verifies the URL. All other functions must pass `method` explicitly (`'POST'`, `'PATCH'`, `'DELETE'`) and tests verify it with `expect.objectContaining({ method: '...' })`.

### Implementation (`client.js`) to make tests green

```js
export class ApiError extends Error {
  constructor(msg, status, data) {
    super(msg);
    this.name = 'ApiError';
    this.status = status;
    this.data = data;
  }
}

async function apiFetch(path, options = {}) {
  const headers = {};
  if (options.body !== undefined) headers['Content-Type'] = 'application/json';
  const response = await fetch(path, { ...options, headers: { ...headers, ...options.headers } });
  // (error handling added in subtask 2, JSON parsing in subtask 3)
  return response.json();
}

export async function fetchCards()              { return apiFetch('/api/cards'); }
export async function createCard(data)          { return apiFetch('/api/cards', { method:'POST', body:JSON.stringify(data) }); }
export async function updateCard(id, data)      { return apiFetch(`/api/cards/${id}`, { method:'PATCH', body:JSON.stringify(data) }); }
export async function deleteCard(id)            { return apiFetch(`/api/cards/${id}`, { method:'DELETE' }); }
export async function createComment(cardId, data) { return apiFetch(`/api/cards/${cardId}/comments`, { method:'POST', body:JSON.stringify(data) }); }
```

